import { prisma } from "@/lib/prisma";
import { getNextAdminProps } from "@premieroctet/next-admin/appRouter";
import { NextAdmin } from "@premieroctet/next-admin/adapters/next";
import "@premieroctet/next-admin/theme";
import { User as UserIcon, Package, ShoppingCart, List, ExternalLink } from "lucide-react";
import AdminDashboard from "@/components/AdminDashboard";
import bcrypt from "bcryptjs";

export default async function AdminPage(props: {
  params: Promise<{ nextadmin: string[] }>;
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>;
}) {
  const params = await props.params;
  const searchParams = await props.searchParams;

  // Busca usuários recentes para o dashboard
  const latestUsers = await prisma.user.findMany({
    select: {
      id: true,
      name: true,
      email: true,
      role: true,
    },
    take: 5,
    orderBy: { createdAt: 'desc' }
  });

  const adminProps = await getNextAdminProps({
    prisma: prisma as any,
    basePath: "/admin",
    apiBasePath: "/api/admin",
    params: params.nextadmin,
    searchParams: searchParams,
    options: {
      title: "Administração Lojinha",
      dashboard: {
        component: (props) => <AdminDashboard {...props} latestUsers={latestUsers} />,
      },
      externalLinks: [
        {
          label: "Voltar para Loja",
          url: "/",
        },
      ],
      model: {
        User: {
          title: "Controle de Usuários",
          display: ["name", "email", "role"],
          search: ["name", "email"],
          fields: {
            name: { label: "Nome" },
            email: { label: "E-mail" },
            password: { 
              label: "Senha",
              hide: true,
            },
            role: { 
              label: "Cargo",
              display: "select",
              options: [
                { label: "Usuário", value: "USER" },
                { label: "Administrador", value: "ADMIN" },
              ],
            },
          },
          middlewares: {
            create: async (data) => {
              if (data.password) {
                data.password = await bcrypt.hash(data.password, 10);
              }
              return data;
            },
            update: async (data) => {
              if (data.password && typeof data.password === 'string' && !data.password.startsWith("$2b$")) {
                data.password = await bcrypt.hash(data.password, 10);
              }
              return data;
            },
          }
        },
        Product: {
          title: "Catálogo de Produtos",
          display: ["name", "category", "price", "stock"],
          search: ["name", "category"],
          fields: {
            id: { hide: true },
            name: { label: "Nome do Produto" },
            category: { 
              label: "Categoria",
              display: "select",
              options: [
                { label: "Uniforme", value: "Uniforme" },
                { label: "Vestuário", value: "Vestuário" },
                { label: "Equipamento", value: "Equipamento" },
                { label: "Distintivos", value: "Distintivos" },
                { label: "Geral", value: "Geral" },
              ],
            },
            price: { 
              label: "Preço",
              format: "currency" 
            },
            stock: { label: "Estoque" },
            description: { label: "Descrição Técnica" },
            image: { 
              label: "Foto",
              display: "image" 
            },
          },
        },
        Sale: {
          title: "Histórico de Vendas",
          display: ["createdAt", "total", "user"],
          fields: {
            id: { label: "Cód. Venda" },
            total: { 
              label: "Faturamento",
              format: "currency" 
            },
            createdAt: { 
              label: "Data/Hora",
              format: "date" 
            },
            user: { label: "Operador" },
            items: { label: "Itens" },
          }
        },
        SaleItem: {
          title: "Itens de Venda",
          display: ["product", "quantity", "unitPrice"],
          fields: {
            id: { hide: true },
            product: { label: "Produto" },
            quantity: { label: "Qtd" },
            unitPrice: { 
              label: "Vlr Unit.",
              format: "currency" 
            },
          }
        }
      }
    },
  });

  return <NextAdmin {...adminProps} />;
}
